document.addEventListener("DOMContentLoaded",()=>{const l=document.querySelector(".site-header");l&&window.addEventListener("scroll",()=>{l.classList.toggle("scrolled",window.scrollY>10)},{passive:!0});const s=document.querySelector(".menu-toggle"),c=document.querySelector(".mobile-nav");s&&c&&(s.addEventListener("click",()=>{const e=c.classList.toggle("open");s.classList.toggle("active",e),document.body.style.overflow=e?"hidden":""}),c.querySelectorAll("a").forEach(e=>{e.addEventListener("click",()=>{c.classList.remove("open"),s.classList.remove("active"),document.body.style.overflow=""})}));const n=document.querySelectorAll(".fade-up");if(n.length&&"IntersectionObserver"in window){const e=new IntersectionObserver(t=>t.forEach(o=>{o.isIntersecting&&(o.target.classList.add("visible"),e.unobserve(o.target))}),{threshold:.1,rootMargin:"0px 0px -40px 0px"});n.forEach(t=>e.observe(t))}else n.forEach(e=>e.classList.add("visible"));document.querySelectorAll(".accordion-trigger").forEach(e=>{e.addEventListener("click",()=>{const t=e.closest(".accordion-item"),o=t.querySelector(".accordion-content"),i=t.classList.contains("open");t.parentElement?.querySelectorAll(".accordion-item.open").forEach(r=>{r!==t&&(r.classList.remove("open"),r.querySelector(".accordion-content").style.maxHeight="0")}),t.classList.toggle("open",!i),o.style.maxHeight=i?"0":o.scrollHeight+"px"})})});
